const lead = $input.first().json;
const contactedDate = new Date(lead['Contacted Date']);
const today = new Date();
const daysSince = Math.floor((today - contactedDate) / (1000 * 60 * 60 * 24));
const followUpCount = parseInt(lead['Follow-up Count'] || '0');

let shouldSend = false;
let emailType = '';
if (followUpCount === 0 && daysSince >= 3) { shouldSend = true; emailType = 'follow_up_1'; }
else if (followUpCount === 1 && daysSince >= 7) { shouldSend = true; emailType = 'follow_up_2'; }
else if (followUpCount === 2 && daysSince >= 14) { shouldSend = true; emailType = 'follow_up_3'; }

return shouldSend ? [{ json: { ...lead, emailType, daysSince } }] : [];
